if (!defined('ABSPATH')) exit;

class MUFU_User_File_Uploads {
    const NONCE_ACTION = 'mufu_upload_action';
    const NONCE_NAME = 'mufu_nonce';
    const FORM_FIELD = 'mufu_file';
    const TYPE_FIELD = 'mufu_type';

    public function __construct() {
        add_shortcode('user_file_upload', [$this, 'shortcode']);
        add_action('init', [$this, 'handle_upload']);
        add_filter('upload_mimes', [$this, 'allow_mimes']);
    }

    public function allow_mimes($mimes) {
        $mimes['pdf']  = 'application/pdf';
        $mimes['doc']  = 'application/msword';
        $mimes['docx'] = 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
        $mimes['xls']  = 'application/vnd.ms-excel';
        $mimes['xlsx'] = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
        $mimes['ppt']  = 'application/vnd.ms-powerpoint';
        $mimes['pptx'] = 'application/vnd.openxmlformats-officedocument.presentationml.presentation';
        $mimes['txt']  = 'text/plain';
        $mimes['rtf']  = 'application/rtf';
        $mimes['csv']  = 'text/csv';
        $mimes['zip']  = 'application/zip';

        $mimes['jpg|jpeg|jpe'] = 'image/jpeg';
        $mimes['png']          = 'image/png';
        $mimes['gif']          = 'image/gif';
        $mimes['webp']         = 'image/webp';
        $mimes['heic']         = 'image/heic';
        $mimes['bmp']          = 'image/bmp';
        $mimes['tif|tiff']     = 'image/tiff';

        return $mimes;
    }

    private function base_dir() {
        $uploads = wp_upload_dir();
        $dir = trailingslashit($uploads['basedir']) . 'user-files';
        return $dir;
    }

    private function base_url() {
        $uploads = wp_upload_dir();
        $url = trailingslashit($uploads['baseurl']) . 'user-files';
        return $url;
    }

    private function user_dir($user_id) {
        return trailingslashit($this->base_dir()) . 'user-' . intval($user_id);
    }

    private function ensure_dirs($user_id) {
        $base = $this->base_dir();
        if (!file_exists($base)) {
            wp_mkdir_p($base);
        }
        $ud = $this->user_dir($user_id);
        if (!file_exists($ud)) {
            wp_mkdir_p($ud);
        }
        $htaccess = trailingslashit($base) . '.htaccess';
        if (!file_exists($htaccess)) {
            @file_put_contents($htaccess, "Options -Indexes\n");
        }
        $index = trailingslashit($base) . 'index.php';
        if (!file_exists($index)) {
            @file_put_contents($index, "<?php\n// Silence is golden.\n");
        }
        $uindex = trailingslashit($ud) . 'index.php';
        if (!file_exists($uindex)) {
            @file_put_contents($uindex, "<?php\n// Silence is golden.\n");
        }
    }

    private function sanitize_upload_type($type) {
        $type = is_string($type) ? strtolower(trim($type)) : '';
        if (!in_array($type, ['profile', 'document'], true)) {
            $type = 'document';
        }
        return $type;
    }

    private function get_allowed_exts() {
        return [
            'jpg','jpeg','png','gif','webp','heic','bmp','tif','tiff',
            'pdf','doc','docx','xls','xlsx','ppt','pptx','txt','rtf','csv','zip'
        ];
    }

    private function ext_from_name($name) {
        $name = (string)$name;
        $ext = strtolower(pathinfo($name, PATHINFO_EXTENSION));
        return $ext;
    }

    private function unique_filename($dir, $filename) {
        $filename = sanitize_file_name($filename);
        if ($filename === '') $filename = 'upload';
        $ext = $this->ext_from_name($filename);
        $name = $ext ? substr($filename, 0, - (strlen($ext) + 1)) : $filename;
        $name = sanitize_title($name);
        if ($name === '') $name = 'file';
        $candidate = $name . ($ext ? '.' . $ext : '');
        $i = 1;
        while (file_exists(trailingslashit($dir) . $candidate)) {
            $candidate = $name . '-' . $i . ($ext ? '.' . $ext : '');
            $i++;
        }
        return $candidate;
    }

    private function verify_filetype($tmp_name, $original_name) {
        $allowed = $this->get_allowed_exts();
        $ext = $this->ext_from_name($original_name);
        if (!$ext || !in_array($ext, $allowed, true)) {
            return [false, 'File type not allowed.'];
        }

        $ft = wp_check_filetype_and_ext($tmp_name, $original_name);
        if (empty($ft['ext']) || empty($ft['type'])) {
            return [false, 'Unable to verify file type.'];
        }

        if (!in_array(strtolower($ft['ext']), $allowed, true)) {
            return [false, 'File type not allowed.'];
        }

        return [true, $ft];
    }

    public function handle_upload() {
        if (!is_user_logged_in()) return;
        if (empty($_POST['mufu_action']) || $_POST['mufu_action'] !== 'upload') return;

        if (!isset($_POST[self::NONCE_NAME]) || !wp_verify_nonce($_POST[self::NONCE_NAME], self::NONCE_ACTION)) {
            $this->set_flash('error', 'Security check failed.');
            $this->redirect_back();
        }

        if (empty($_FILES[self::FORM_FIELD]) || !is_array($_FILES[self::FORM_FIELD])) {
            $this->set_flash('error', 'No file selected.');
            $this->redirect_back();
        }

        $file = $_FILES[self::FORM_FIELD];

        if (!isset($file['error']) || is_array($file['error'])) {
            $this->set_flash('error', 'Invalid upload.');
            $this->redirect_back();
        }

        if ($file['error'] !== UPLOAD_ERR_OK) {
            $this->set_flash('error', $this->upload_error_message($file['error']));
            $this->redirect_back();
        }

        if (empty($file['tmp_name']) || !is_uploaded_file($file['tmp_name'])) {
            $this->set_flash('error', 'Upload failed.');
            $this->redirect_back();
        }

        $user_id = get_current_user_id();
        $type = $this->sanitize_upload_type($_POST[self::TYPE_FIELD] ?? 'document');

        $this->ensure_dirs($user_id);
        $user_dir = $this->user_dir($user_id);

        list($ok, $ft) = $this->verify_filetype($file['tmp_name'], $file['name']);
        if (!$ok) {
            $this->set_flash('error', $ft);
            $this->redirect_back();
        }

        $max_bytes = (int)apply_filters('mufu_max_upload_bytes', 25 * 1024 * 1024, $user_id, $type);
        if ($max_bytes > 0 && (int)$file['size'] > $max_bytes) {
            $this->set_flash('error', 'File is too large.');
            $this->redirect_back();
        }

        $subdir = trailingslashit($user_dir) . ($type === 'profile' ? 'profile' : 'documents');
        if (!file_exists($subdir)) {
            wp_mkdir_p($subdir);
            $idx = trailingslashit($subdir) . 'index.php';
            if (!file_exists($idx)) @file_put_contents($idx, "<?php\n// Silence is golden.\n");
        }

        $safe_name = $this->unique_filename($subdir, $file['name']);
        $dest = trailingslashit($subdir) . $safe_name;

        if (!@move_uploaded_file($file['tmp_name'], $dest)) {
            $this->set_flash('error', 'Could not save the uploaded file.');
            $this->redirect_back();
        }

        @chmod($dest, 0644);

        $rel = str_replace(trailingslashit($this->base_dir()), '', $dest);
        $meta = [
            'path' => $dest,
            'relative' => $rel,
            'url' => trailingslashit($this->base_url()) . str_replace(DIRECTORY_SEPARATOR, '/', $rel),
            'name' => $safe_name,
            'original_name' => sanitize_text_field($file['name']),
            'type' => $type,
            'mime' => $ft['type'],
            'ext' => $ft['ext'],
            'size' => (int)$file['size'],
            'time' => time(),
        ];

        if ($type === 'profile') {
            update_user_meta($user_id, 'mufu_profile_file', $meta);
            $this->set_flash('success', 'Profile picture uploaded.');
        } else {
            $docs = get_user_meta($user_id, 'mufu_documents', true);
            if (!is_array($docs)) $docs = [];
            $docs[] = $meta;
            update_user_meta($user_id, 'mufu_documents', $docs);
            $this->set_flash('success', 'Document uploaded.');
        }

        $this->redirect_back();
    }

    private function upload_error_message($code) {
        switch ($code) {
            case UPLOAD_ERR_INI_SIZE:
            case UPLOAD_ERR_FORM_SIZE:
                return 'File is too large.';
            case UPLOAD_ERR_PARTIAL:
                return 'File was only partially uploaded.';
            case UPLOAD_ERR_NO_FILE:
                return 'No file was uploaded.';
            case UPLOAD_ERR_NO_TMP_DIR:
                return 'Missing a temporary folder.';
            case UPLOAD_ERR_CANT_WRITE:
                return 'Failed to write file to disk.';
            case UPLOAD_ERR_EXTENSION:
                return 'A PHP extension stopped the file upload.';
            default:
                return 'Upload error.';
        }
    }

    private function set_flash($key, $message) {
        if (!session_id()) {
            @session_start();
        }
        $_SESSION['mufu_flash'][$key] = $message;
    }

    private function get_flash($key) {
        if (!session_id()) {
            @session_start();
        }
        if (!empty($_SESSION['mufu_flash'][$key])) {
            $msg = $_SESSION['mufu_flash'][$key];
            unset($_SESSION['mufu_flash'][$key]);
            return $msg;
        }
        return '';
    }

    private function redirect_back() {
        $redirect = wp_get_referer();
        if (!$redirect) $redirect = home_url('/');
        wp_safe_redirect($redirect);
        exit;
    }

    public function shortcode($atts) {
        if (!is_user_logged_in()) {
            return '<p>You must be logged in to upload files.</p>';
        }

        $atts = shortcode_atts([
            'type' => 'document',
            'label' => '',
            'button' => 'Upload',
            'show_list' => '1',
        ], $atts, 'user_file_upload');

        $type = $this->sanitize_upload_type($atts['type']);
        $label = $atts['label'] !== '' ? $atts['label'] : ($type === 'profile' ? 'Upload Profile Picture' : 'Upload Document');
        $button = $atts['button'] !== '' ? $atts['button'] : 'Upload';
        $show_list = $atts['show_list'] === '1';

        $success = esc_html($this->get_flash('success'));
        $error = esc_html($this->get_flash('error'));

        $accept = implode(',', array_map(function($e){ return '.' . $e; }, $this->get_allowed_exts()));

        $out = '';
        if ($success) $out .= '<div class="mufu-notice mufu-success" style="padding:10px;margin:10px 0;border:1px solid #46b450;background:#ecf7ed;">' . $success . '</div>';
        if ($error) $out .= '<div class="mufu-notice mufu-error" style="padding:10px;margin:10px 0;border:1px solid #dc3232;background:#fbeaea;">' . $error . '</div>';

        $out .= '<form method="post" enctype="multipart/form-data">';
        $out .= '<p><strong>' . esc_html($label) . '</strong></p>';
        $out .= '<input type="hidden" name="mufu_action" value="upload" />';
        $out .= '<input type="hidden" name="' . esc_attr(self::TYPE_FIELD) . '" value="' . esc_attr($type) . '" />';
        $out .= wp_nonce_field(self::NONCE_ACTION, self::NONCE_NAME, true, false);
        $out .= '<p><input type="file" name="' . esc_attr(self::FORM_FIELD) . '" accept="' . esc_attr($accept) . '" required /></p>';
        $out .= '<p><button type="submit">' . esc_html($button) . '</button></p>';
        $out .= '</form>';

        if ($show_list) {
            $user_id = get_current_user_id();
            if ($type === 'profile') {
                $meta = get_user_meta($user_id, 'mufu_profile_file', true);
                if (is_array($meta) && !empty($meta['url'])) {
                    $url = esc_url($meta['url']);
                    $name = esc_html($meta['original_name'] ?? $meta['name'] ?? '');
                    $out .= '<div class="mufu-current">';
                    $out .= '<p><strong>Current profile file:</strong> <a href="' . $url . '" target="_blank" rel="noopener">' . $name . '</a></p>';
                    if (!empty($meta['mime']) && strpos($meta['mime'], 'image/') === 0) {
                        $out .= '<p><img src="' . $url . '" alt="" style="max-width:200px;height:auto;" /></p>';
                    }
                    $out .= '</div>';
                }
            } else {
                $docs = get_user_meta($user_id, 'mufu_documents', true);
                if (is_array($docs) && !empty($docs)) {
                    $out .= '<div class="mufu-docs"><p><strong>Your uploaded documents:</strong></p><ul>';
                    $docs = array_reverse($docs);
                    $count = 0;
                    foreach ($docs as $d) {
                        if (!is_array($d) || empty($d['url'])) continue;
                        $url = esc_url($d['url']);
                        $name = esc_html($d['original_name'] ?? $d['name'] ?? 'file');
                        $time = !empty($d['time']) ? date_i18n(get_option('date_format') . ' ' . get_option('time_format'), (int)$d['time']) : '';
                        $out .= '<li><a href="' . $url . '" target="_blank" rel="noopener">' . $name . '</a>' . ($time ? ' <small>(' . esc_html($time) . ')</small>' : '') . '</li>';
                        $count++;
                        if ($count >= 20) break;
                    }
                    $out .= '</ul></div>';
                }
            }
        }

        return $out;
    }
}

new MUFU_User_File_Uploads();